SELECT DISTINCT u.username
FROM users u
INNER JOIN ratings r ON u.user_id = r.user_id;

SELECT AVG(rating) AS average_rating
FROM movies
WHERE production_companies LIKE '%Company XYZ%';

SELECT title
FROM movies
WHERE revenue = (SELECT MAX(revenue) FROM movies);

SELECT AVG(movies.rating) AS average_rating
FROM movies
WHERE movies.production_companies LIKE '%20th Century Fox%' AND movies.release_date > '2010-01-01';
